import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    const reverseAdj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        reverseAdj[v].push([u, w]);
    }

    // dist[0][u] = cost without using switch at u
    // dist[1][u] = cost using switch at u
    const dist = Array.from({ length: 2 }, () => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const pq = new MinPriorityQueue({ priority: (node) => node.cost });
    pq.enqueue({ u: 0, usedSwitch: 0, cost: 0 });

    while (!pq.isEmpty()) {
        const { u, usedSwitch, cost } = pq.dequeue().element;
        if (u === n - 1) {
            return cost;
        }
        if (cost > dist[usedSwitch][u]) {
            continue;
        }

        // Option 1: Do not use switch at u (if not used yet)
        if (usedSwitch === 0) {
            for (const [v, w] of adj[u]) {
                const newCost = cost + w;
                if (newCost < dist[0][v]) {
                    dist[0][v] = newCost;
                    pq.enqueue({ u: v, usedSwitch: 0, cost: newCost });
                }
            }
        }

        // Option 2: Use switch at u (if not used yet)
        if (usedSwitch === 0) {
            for (const [v, w] of reverseAdj[u]) {
                const newCost = cost + 2 * w;
                if (newCost < dist[1][v]) {
                    dist[1][v] = newCost;
                    pq.enqueue({ u: v, usedSwitch: 1, cost: newCost });
                }
            }
        } else {
            // If switch is already used, just proceed normally
            for (const [v, w] of adj[u]) {
                const newCost = cost + w;
                if (newCost < dist[1][v]) {
                    dist[1][v] = newCost;
                    pq.enqueue({ u: v, usedSwitch: 1, cost: newCost });
                }
            }
        }
    }

    const res = Math.min(dist[0][n - 1], dist[1][n - 1]);
    return res === Infinity ? -1 : res;
}

